#!/bin/bash

# Check if AWS CLI is installed
if ! command -v aws &> /dev/null; then
    echo "AWS CLI could not be found, please install it first."
    exit 1
fi

# Authenticate with AWS using environment variables or credentials file
if [ -z "$AWS_ACCESS_KEY_ID" ] || [ -z "$AWS_SECRET_ACCESS_KEY" ]; then
    echo "AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY must be set as environment variables."
    exit 1
fi

# Set the default region (can be overridden by setting AWS_DEFAULT_REGION)
export AWS_DEFAULT_REGION="${AWS_DEFAULT_REGION:-us-east-1}"

# Example deployment operation: Create an S3 bucket
BUCKET_NAME="my-deployment-bucket-$(date +%s)"
aws s3api create-bucket --bucket "$BUCKET_NAME" --region "$AWS_DEFAULT_REGION"

if [ $? -eq 0 ]; then
    echo "S3 Bucket created successfully: $BUCKET_NAME"
else
    echo "Failed to create S3 Bucket."
    exit 1
fi

